# app/flags.py
"""
Typed feature flag client with safe defaults from the registry.
Reads from LaunchDarkly / GrowthBook / custom flag store.
Falls back to default_value from registry if flag is unavailable.
"""
import os, yaml, functools
from pathlib import Path

# Load registry defaults at startup — fail-safe values
_REGISTRY_PATH = Path("flags/registry.yaml")

@functools.lru_cache(maxsize=1)
def _load_defaults() -> dict[str, any]:
    if not _REGISTRY_PATH.exists():
        return {}
    with open(_REGISTRY_PATH) as f:
        data = yaml.safe_load(f)
    return {flag["key"]: flag["default_value"] for flag in data.get("flags", [])}

def _get_flag_client():
    """Return the flag store client (LaunchDarkly, GrowthBook, etc)."""
    # In tests, inject a mock via FLAG_CLIENT env var
    provider = os.environ.get("FLAG_PROVIDER", "launchdarkly")
    if provider == "mock":
        return None   # fallback to defaults
    import ldclient
    return ldclient.get()

def get_bool(key: str, user_context: dict | None = None) -> bool:
    """Read a boolean feature flag with safe default."""
    client = _get_flag_client()
    default = _load_defaults().get(key, False)
    if client is None:
        return default
    try:
        return client.variation(key, user_context or {"key": "anonymous"}, default)
    except Exception:
        return default   # never raise on flag read failure

def get_str(key: str, user_context: dict | None = None) -> str:
    client = _get_flag_client()
    default = _load_defaults().get(key, "")
    if client is None:
        return default
    try:
        return client.variation(key, user_context or {"key": "anonymous"}, default)
    except Exception:
        return default

# Usage in application code
from app.flags import get_bool

def rank_results(results: list, user_id: str) -> list:
    user_ctx = {"key": user_id}
    if get_bool("genai.experimental_ranking", user_ctx):
        return rank_v2(results)
    return rank_v1(results)
